import { Component, OnInit, ViewChild } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { IonCheckbox, IonSegment, IonSelect } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { ClientTransactionsService } from "src/app/core/services/client-transactions.service";
import { pagingService } from "src/app/core/services/paging.service";
import { PostingFinancialTransactions } from "src/app/views/Models/ClientTransactions/PostingFinancialTransactions";
import { TransType } from "src/app/views/Models/ClientTransactions/TransType";

interface CheckPageTypes {
  isPostingClientTransaction: boolean;
  isPostingCancelClientTransaction: boolean;
  isPostingApplicationTransactions: boolean;
  isPostingCancelApplicationTransactions: boolean;
}

@Component({
  selector: "app-post-financial-transactions",
  templateUrl: "./post-financial-transactions.page.html",
  styleUrls: ["./post-financial-transactions.page.css"],
})
export class PostFinancialTransactionsPage implements OnInit {
  @ViewChild("ionCheckBox") ionCheckBox: IonCheckbox;
  @ViewChild("ionSegment") ionSegment: IonSegment;
  @ViewChild("transTypeSelect", { static: false }) transTypeSelect: IonSelect;

  //region Variables
  showLoader: boolean = false;
  pageTypeAccessRights: any[];
  checkPageTypes: CheckPageTypes = {
    isPostingClientTransaction: false,
    isPostingCancelClientTransaction: false,
    isPostingApplicationTransactions: false,
    isPostingCancelApplicationTransactions: false,
  };
  windowCodesToCheck: any[] = ["5639", "5640", "5641", "5642"];
  PostingFinancialTransactionPageType: any[] = [
    {
      pageTypeDesc: "تنفيذ حركات العميل",
      pageCode: 5639,
      pageAction: 1,
    },
    {
      pageTypeDesc: "تنفيذ الغاء حركات العميل",
      pageCode: 5640,
      pageAction: 2,
    },
    {
      pageTypeDesc: "تنفيذ حركات طلب القرض",
      pageCode: 5641,
      pageAction: 3,
    },
    {
      pageTypeDesc: "تنفيذ الغاء حركات طلب القرض",
      pageCode: 5642,
      pageAction: 4,
    },
  ];
  pageType: any;
  postingFinancialTransactions: Array<
    PostingFinancialTransactions & { isChecked: boolean }
  >;
  TransactionPage: number = 1;
  selectedTransactions: PostingFinancialTransactions[];
  TransTypes: TransType[];
  selectedTransTypes: number[];
  searched: boolean = false;
  segmentSelected: boolean = false;
  transType: number;
  cancel: number;
  selectAllValues = -1;
  TypeForm: FormGroup = this.FormBuilder.group({
    trans_type: [null, [Validators.required]],
  });
  //endregion

  constructor(
    private authService: MohassilAuthService,
    public pagingService: pagingService,
    private clientTransactionService: ClientTransactionsService,
    private alertService: AlertService,
    private FormBuilder: FormBuilder
  ) {}

  async ngOnInit() {
    this.pageTypeAccessRights = await this.authService.getAccessRights();
    // Filter the clientTransactionPageType array according to access rights
    const filteredClientTransactionPageTypes =
      this.PostingFinancialTransactionPageType.filter((page) => {
        return this.windowCodesToCheck.some(
          (x) => x === page.pageCode.toString() && this.checkWindowCodeExists(x)
        );
      });
    this.PostingFinancialTransactionPageType =
      filteredClientTransactionPageTypes;

    await this.getTransactionTypes(
      this.PostingFinancialTransactionPageType[0].pageCode.toString()
    );
    this.postingFinancialTransactions = [];
    this.ionSegment.value =
      this.PostingFinancialTransactionPageType[0].pageCode.toString();
  }

  //region Ion Select
  async SearchByTransType() {
    //console.log(this.TypeForm.controls.trans_type.value.join(','))
    await this.getTransactions(
      this.transType,
      this.TypeForm.controls.trans_type.value.join(",")
    );
    this.searched = true;
  }
  //endregion

  //region Ion Segment
  async changePageType(event) {
    this.TypeForm.reset();
    if (event.detail.value.toString() === "0") return;
    this.pageType = this.PostingFinancialTransactionPageType.find(
      (x) => x.pageCode.toString() === event.detail.value.toString()
    );
    this.checkPageTypes.isPostingClientTransaction =
      this.checkWindowCodeExists("5639");
    this.checkPageTypes.isPostingCancelClientTransaction =
      this.checkWindowCodeExists("5640");
    this.checkPageTypes.isPostingApplicationTransactions =
      this.checkWindowCodeExists("5641");
    this.checkPageTypes.isPostingCancelApplicationTransactions =
      this.checkWindowCodeExists("5642");

    await this.getTransactionTypes(this.pageType.pageCode.toString());
    this.searched = false;
  }
  checkWindowCodeExists = (WindowCode: string): boolean => {
    return this.pageTypeAccessRights.some((x) => x.window_code === WindowCode);
  };
  async getTransactionTypes(pageCode: string) {
    switch (pageCode) {
      case "5639": {
        this.checkPageTypes.isPostingClientTransaction = true;
        this.checkPageTypes.isPostingCancelClientTransaction = false;
        this.checkPageTypes.isPostingApplicationTransactions = false;
        this.checkPageTypes.isPostingCancelApplicationTransactions = false;
        this.transType = 2;
        this.cancel = 0;
        break;
      }
      case "5640": {
        this.checkPageTypes.isPostingClientTransaction = false;
        this.checkPageTypes.isPostingCancelClientTransaction = true;
        this.checkPageTypes.isPostingApplicationTransactions = false;
        this.checkPageTypes.isPostingCancelApplicationTransactions = false;
        this.transType = 2;
        this.cancel = 1;
        break;
      }
      case "5641": {
        this.checkPageTypes.isPostingClientTransaction = false;
        this.checkPageTypes.isPostingCancelClientTransaction = false;
        this.checkPageTypes.isPostingApplicationTransactions = true;
        this.checkPageTypes.isPostingCancelApplicationTransactions = false;
        this.transType = 3;
        this.cancel = 0;
        break;
      }
      case "5642": {
        this.checkPageTypes.isPostingClientTransaction = false;
        this.checkPageTypes.isPostingCancelClientTransaction = false;
        this.checkPageTypes.isPostingApplicationTransactions = false;
        this.checkPageTypes.isPostingCancelApplicationTransactions = true;
        this.transType = 3;
        this.cancel = 1;
        break;
      }
    }
    this.showLoader = true;
    this.TransTypes = await this.clientTransactionService
      .GetTransType(this.transType, this.cancel)
      .toPromise();
    this.showLoader = false;
    this.segmentSelected = true;
  }

  async getTransactions(transType: number, transKey: string) {
    this.TransactionPage = 1;
    this.selectedTransactions = [];
    this.showLoader = true;
    this.postingFinancialTransactions = [];
    if (transKey) {
      this.postingFinancialTransactions = (
        await this.clientTransactionService
          .GetFinancialTransactions(transType, transKey)
          .toPromise()
      ).map((x) => ({
        ...x,
        isChecked: false,
      }));
    }
    this.showLoader = false;
  }
  //endregion

  //region Checbox
  set isAllSelected(value: boolean) {
    this.postingFinancialTransactions.forEach(
      (trans) => (trans.isChecked = value)
    );
  }
  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.postingFinancialTransactions.forEach(
      (trans) => (trans.isChecked = isChecked)
    );
    this.updateSelectedLoanForAll(isChecked);
  }
  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedTransactions = [];
    if (isChecked) {
      this.postingFinancialTransactions.forEach((trans) => {
        this.selectedTransactions.push(trans);
      });
    }
  }
  onCheckboxChange(event: any, trans: any, index: any) {
    const selectedApp =
      this.postingFinancialTransactions[
        index + this.pagingService.pageSize * (this.TransactionPage - 1)
      ];

    selectedApp.isChecked = event.target.checked;
    this.updateSelectedApplicaiton(trans, event.target.checked);
    this.updateMasterCheckbox();
    if (
      this.postingFinancialTransactions.length !==
      this.selectedTransactions.length
    ) {
      if (this.selectedTransactions.length === 0) {
        this.ionCheckBox.indeterminate = false;
      } else {
        this.ionCheckBox.indeterminate = true;
      }
    } else if (
      this.postingFinancialTransactions.length ===
      this.selectedTransactions.length
    ) {
      this.ionCheckBox.indeterminate = false;
      this.ionCheckBox.checked = true;
      this.isAllSelected = true;
    }
  }
  updateSelectedApplicaiton(trans: any, isChecked: boolean) {
    const index = this.selectedTransactions.indexOf(trans);
    if (isChecked && index === -1) {
      this.selectedTransactions.push(trans);
    } else if (!isChecked && index > -1) {
      this.selectedTransactions.splice(index, 1);
    }
  }
  updateMasterCheckbox() {
    const allSelected = this.postingFinancialTransactions.every(
      (app) => app.isChecked
    );
    const someSelected = this.postingFinancialTransactions.some(
      (app) => app.isChecked
    );

    if (allSelected) {
      this.isAllSelected = true;
    } else if (!someSelected) {
      this.ionCheckBox.checked = false;
      this.ionCheckBox.indeterminate = false;
      this.isAllSelected = false;
    }
  }
  changePaginationPage = (newPage: number): void => {
    this.TransactionPage = newPage;
  };
  //endregion

  //region Submit & Back
  async postTransactions() {
    if (await this.alertService.SaveAlert("هل انت متاكد من التنفيذ؟")) {
      //console.log("this.selectedTransactions:" , this.selectedTransactions)
      this.showLoader = true;
      this.clientTransactionService
        .postFinancialTransactions(this.selectedTransactions)
        .subscribe({
          next: async () => {
            this.showLoader = false;
            await this.alertService.showAlertConfirm("تم الحفظ بنجاح", false);
            await this.getTransactions(
              this.transType,
              this.TypeForm.controls.trans_type.value.join(",")
            );
          },
          error: async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }
  backbtn() {
    this.segmentSelected = false;
    this.isAllSelected = false;
    this.postingFinancialTransactions = [];
    this.selectedTransactions = [];
    this.TransactionPage = 1;
    this.ionSegment.value = "0";
    this.searched = false;
  }
  //endregion
}
